+    }
+
+    #[test]
+    fn timedelta_div_timedelta_nat_returns_nan() {
+        assert!(Timedelta::div_timedelta(Timedelta::NAT, 100).is_nan());
+        assert!(Timedelta::div_timedelta(100, Timedelta::NAT).is_nan());
+    }
